 * The cost for store i is min(prices[i], min_{j} (shortest_path_no_apple(i -> j) + prices[j] + shortest_path_with_apple(j -> i))).
 * Since the roads are bidirectional, shortest_path_no_apple(i -> j) = shortest_path_no_apple(j -> i).
 * Similarly, shortest_path_with_apple(j -> i) = shortest_path_with_apple(i -> j).
 *
 * Let D_no[i][j] be the shortest path cost from i to j without carrying apples (cost * 1).
 * Let D_yes[i][j] be the shortest path cost from i to j while carrying apples (cost * tax).
 *
 * The problem states:
 * 1. Direct purchase at i: prices[i]
 * 2. Go empty hand from i to j, buy at j, return with apple to i:
 *    Cost = D_no[i][j] + prices[j] + D_yes[j][i]
 *
 * Since roads are bidirectional:
 * D_no[i][j] = D_no[j][i] (using cost)
 * D_yes[j][i] = D_yes[i][j] (using cost * tax)
 *
 * Total cost for route i -> j -> i: D_no[i][j] + prices[j] + D_yes[i][j]
 *
 * We need to find: ans[i] = min(prices[i], min_{j} (D_no[i][j] + prices[j] + D_yes[i][j]))
 *
 * D_no[i][j] is the shortest path distance using edge costs 'cost_i'.
 * D_yes[i][j] is the shortest path distance using edge costs 'cost_i * tax_i'.
 */
fun solve(n: Long, prices: Array<Long>, roads: Array<Array<Long>>): Array<Long> {
    val N = n.toInt()

    // Adjacency lists for two different scenarios:
    // 1. No apple: weight = cost
    val adjNoApple = Array(N) { mutableListOf<Edge>() }
    // 2. With apple: weight = cost * tax
    val adjWithApple = Array(N) { mutableListOf<Edge>() }

    for (road in roads) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        val tax = road[3]

        // No apple (weight = cost)
        adjNoApple[u].add(Edge(v, cost, 0)) // Tax field is ignored for D_no
        adjNoApple[v].add(Edge(u, cost, 0))

        // With apple (weight = cost * tax)
        val taxedCost = cost * tax
        adjWithApple[u].add(Edge(v, taxedCost, 1)) // Tax field set to 1 to distinguish
        adjWithApple[v].add(Edge(u, taxedCost, 1))
    }

    // Dijkstra's algorithm implementation

    // Function to run Dijkstra from a source node s using a specific adjacency list
    fun dijkstra(startNode: Int, adj: Array<MutableList<Edge>>): LongArray {
        val dist = LongArray(N) { Long.MAX_VALUE }
        dist[startNode] = 0L

        // Pair: (distance, node)
        val pq = PriorityQueue<Pair<Long, Int>>(compareBy { it.first })
        pq.add(Pair(0L, startNode))

        while (pq.isNotEmpty()) {
            val (d, u) = pq.poll()

            if (d > dist[u]) continue

            for (edge in adj[u]) {
                val v = edge.to
                // In D_no, edge.cost is the actual cost. In D_yes, edge.cost is the actual cost*tax.
                val weight = edge.cost

                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight
                    pq.add(Pair(dist[v], v))
                }
            }
        }
        return dist
    }

    // 1. Calculate D_no[i][j] for all i, j. Since the graph is undirected, we can run Dijkstra N times.
    // D_no[i] stores the shortest distances from i to all other nodes j.
    val dNo = Array(N) { LongArray(N) }
    for (i in 0 until N) {
        dNo[i] = dijkstra(i, adjNoApple)
    }

    // 2. Calculate D_yes[i][j] for all i, j.
    // D_yes[i] stores the shortest distances from i to all other nodes j while carrying apples.
    val dYes = Array(N) { LongArray(N) }
    for (i in 0 until N) {
        dYes[i] = dijkstra(i, adjWithApple)
    }

    // 3. Calculate the final answer ans[i]
    val ans = LongArray(N)
    for (i in 0 until N) {
        // Option 1: Buy directly at i
        var minCost = prices[i]

        // Option 2: Go i -> j (empty) -> Buy at j -> Return j -> i (with apple)
        for (j in 0 until N) {
            if (i == j) continue // No benefit from buying at i and traveling to i

            // Total cost = D_no[i][j] + prices[j] + D_yes[j][i]

            val pathNoApple = dNo[i][j]
            val pathWithApple = dYes[j][i]

            // Check for unreachable nodes (though constraints suggest connectivity might not be guaranteed,
            // we must handle Long.MAX_VALUE)
            if (pathNoApple != Long.MAX_VALUE && pathWithApple != Long.MAX_VALUE) {
                // Note: D_yes[j][i] is the cost to travel from j to i while carrying the apple purchased at j.
                val totalCost = pathNoApple + prices[j] + pathWithApple
                if (totalCost < minCost) {
                    minCost = totalCost
                }
            }
        }
        ans[i] = minCost
    }

    return ans
}
