import java.util.PriorityQueue
import java.util.Arrays

/**
 * Data class to represent an edge in the graph.
 * cost: cost when carrying no apples (u -> v)
 * tax: multiplier for cost when carrying apples (u -> v)
 * to: destination node
 */
data class Edge(
    val to: Int,
    val costNoApple: Long,
    val costWithApple: Long
)

/**
 * Data class for Dijkstra's algorithm state.
 * node: current node
 * distance: accumulated minimum cost to reach this node
 */
data class State(
    val node: Int,
    val distance: Long
) : Comparable<State> {
    override fun compareTo(other: State): Int {
        return distance.compareTo(other.distance)
    }
}

/**
 * Calculates the minimum cost to acquire apples at each store.
 * 
 * The cost for store i is min(prices[i], min_{j} (min_path_cost(i->j, no_apple) + min_path_cost(j->i, with_apple) + prices[j]))
 * 
 * Since roads are bidirectional:
 * - Path i -> j (no apple): Use cost_i for all edges.
 * - Path j -> i (with apple): Use cost_i * tax_i for all edges.
 * 
 * We need two shortest path calculations:
 * 1. Shortest path from all nodes to node j using only 'cost' (no apple). Let this be dist_no_apple[i][j].
 * 2. Shortest path from all nodes to node j using only 'cost * tax' (with apple). Let this be dist_with_apple[j][i].
 * 
 * However, the problem structure suggests:
 * For store i:
 * Option 1: Buy at i. Cost = prices[i].
 * Option 2: Buy at j, travel i -> j (no apple), travel j -> i (with apple).
 * Cost = min_path_cost(i->j, no_apple) + prices[j] + min_path_cost(j->i, with_apple)
 * 
 * Since roads are bidirectional, if the edge (u, v) has (cost, tax):
 * - i -> j (no apple): Cost is the shortest path using 'cost' on all edges.
 * - j -> i (with apple): Cost is the shortest path using 'cost * tax' on all edges.
 * 
 * We need:
 * - Dist_NoApple[i][j]: Shortest path from i to j using 'cost' on all edges.
 * - Dist_WithApple[j][i]: Shortest path from j to i using 'cost * tax' on all edges.
 * 
 * Due to bidirectionality:
 * - Dist_NoApple[i][j] = Dist_NoApple[j][i] (if we use Dijkstra from a source).
 * - Dist_WithApple[j][i] is the shortest path from j to i using weighted edges.
 * 
 * We can run Dijkstra N times:
 * 1. N runs for 'no apple' cost to find all-pairs shortest paths (APSP) using cost.
 * 2. N runs for 'with apple' cost to find all-pairs shortest paths (APSP) using cost * tax.
 */
fun solve(n: Long, prices: Array<Long>, roads: Array<Array<Long>>): Array<Long> {
    val nInt = n.toInt()

    // Adjacency list representation: adj[u] contains edges connected to u
    // Each edge stores (v, cost_no_apple, cost_with_apple)
    val adj = Array(nInt) { mutableListOf<Edge>() }

    for (road in roads) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        val tax = road[3]

        // Cost with apple: cost * tax
        val costWithApple = cost * tax

        // Roads are bidirectional
        adj[u].add(Edge(v, cost, costWithApple))
        adj[v].add(Edge(u, cost, costWithApple))
    }

    // --- Step 1 & 2: All-Pairs Shortest Path (APSP) using Dijkstra's Algorithm ---

    // distNoApple[i][j]: Shortest path from i to j without apples (using cost)
    val distNoApple = Array(nInt) { LongArray(nInt) { Long.MAX_VALUE } }

    // distWithApple[i][j]: Shortest path from i to j with apples (using cost * tax)
    val distWithApple = Array(nInt) { LongArray(nInt) { Long.MAX_VALUE } }

    // Helper function to run Dijkstra's from a single source using specified edge weights
    fun dijkstra(startNode: Int, adjList: Array<MutableList<Edge>>, isNoApple: Boolean): LongArray {
        val dist = LongArray(nInt) { Long.MAX_VALUE }
        dist[startNode] = 0L
        val pq = PriorityQueue<State>()
        pq.add(State(startNode, 0L))

        while (pq.isNotEmpty()) {
            val (u, d) = pq.poll().let { Pair(it.node, it.distance) }

            if (d > dist[u]) continue

            for (edge in adjList[u]) {
                val v = edge.to
                val weight = if (isNoApple) edge.costNoApple else edge.costWithApple

                if (dist[u] != Long.MAX_VALUE && dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight
                    pq.add(State(v, dist[v]))
                }
            }
        }
        return dist
    }

    // Run N times for No Apple cost
    for (i in 0 until nInt) {
        val dist = dijkstra(i, adj, isNoApple = true)
        for (j in 0 until nInt) {
            distNoApple[i][j] = dist[j]
        }
    }

    // Run N times for With Apple cost
    for (i in 0 until nInt) {
        val dist = dijkstra(i, adj, isNoApple = false)
        for (j in 0 until nInt) {
            distWithApple[i][j] = dist[j]
        }
    }

    // --- Step 3: Calculate the minimum cost for each store i ---

    val ans = LongArray(nInt)

    for (i in 0 until nInt) {
        // Option 1: Buy at i directly
        var minCost = prices[i]

        // Option 2: Buy at some store j, travel i -> j (no apple), travel j -> i (with apple)
        for (j in 0 until nInt) {
